import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void basic() {
        String[][] input = {
            {"FOOD", "Uber Eats"},
            {"RIDE", "Uber"},
            {"FOOD", "Chipotle"},
            {"FOOD", "Uber Eats"}
        };
        Map<String, List<String>> result = new Solution().merchantsByCategory(input);
        assertEquals(Set.of("FOOD", "RIDE"), result.keySet());
        assertEquals(List.of("Uber Eats", "Chipotle", "Uber Eats"), result.get("FOOD"));
        assertEquals(List.of("Uber"), result.get("RIDE"));
    }

    @Test
    void empty() {
        Map<String, List<String>> result = new Solution().merchantsByCategory(new String[][]{});
        assertTrue(result.isEmpty());
    }

    @Test
    void singleTransaction() {
        String[][] input = {{"TRAVEL", "Delta Airlines"}};
        Map<String, List<String>> result = new Solution().merchantsByCategory(input);
        assertEquals(Set.of("TRAVEL"), result.keySet());
        assertEquals(List.of("Delta Airlines"), result.get("TRAVEL"));
    }

    @Test
    void allSameCategory() {
        // adversarial: every transaction under the same category
        String[][] input = {
            {"FOOD", "McDonald's"},
            {"FOOD", "Subway"},
            {"FOOD", "McDonald's"}
        };
        Map<String, List<String>> result = new Solution().merchantsByCategory(input);
        assertEquals(Set.of("FOOD"), result.keySet());
        assertEquals(List.of("McDonald's", "Subway", "McDonald's"), result.get("FOOD"));
    }

    @Test
    void eachCategoryDistinct() {
        // each transaction has a unique category — each bucket has exactly one merchant
        String[][] input = {
            {"GAS", "Shell"},
            {"GROCERY", "Whole Foods"},
            {"PHARMACY", "CVS"}
        };
        Map<String, List<String>> result = new Solution().merchantsByCategory(input);
        assertEquals(Set.of("GAS", "GROCERY", "PHARMACY"), result.keySet());
        assertEquals(List.of("Shell"), result.get("GAS"));
        assertEquals(List.of("Whole Foods"), result.get("GROCERY"));
        assertEquals(List.of("CVS"), result.get("PHARMACY"));
    }

    @Test
    void duplicateMerchantSameCategory() {
        // same merchant appears twice under the same category — both entries kept
        String[][] input = {
            {"COFFEE", "Starbucks"},
            {"COFFEE", "Starbucks"}
        };
        Map<String, List<String>> result = new Solution().merchantsByCategory(input);
        assertEquals(List.of("Starbucks", "Starbucks"), result.get("COFFEE"));
    }

    @Test
    void preservesInsertionOrder() {
        // merchants in a bucket must appear in input order
        String[][] input = {
            {"RETAIL", "Amazon"},
            {"RETAIL", "Target"},
            {"RETAIL", "Walmart"},
            {"RETAIL", "Amazon"}
        };
        Map<String, List<String>> result = new Solution().merchantsByCategory(input);
        assertEquals(List.of("Amazon", "Target", "Walmart", "Amazon"), result.get("RETAIL"));
    }
}
